/**
 * 简化版 Excel 导出库
 * 用于微信小程序生成 Excel 文件
 */

var XLSX = {
  version: "0.20.3-mini"
};

// 工具函数
function s2ab(s) {
  var buf = new ArrayBuffer(s.length);
  var view = new Uint8Array(buf);
  for (var i = 0; i != s.length; ++i) view[i] = s.charCodeAt(i) & 0xFF;
  return buf;
}

function json_to_sheet(data, opts) {
  var o = opts || {};
  var ws = {};
  var range = {s: {c: 0, r: 0}, e: {c: 0, r: 0}};
  
  // 获取所有列名
  var cols = [];
  if (data.length > 0) {
    cols = Object.keys(data[0]);
  }
  
  // 写入表头
  for (var i = 0; i < cols.length; ++i) {
    var cell = {v: cols[i], t: 's'};
    var cell_ref = encode_cell({c: i, r: 0});
    ws[cell_ref] = cell;
  }
  
  // 写入数据
  for (var R = 0; R < data.length; ++R) {
    for (var C = 0; C < cols.length; ++C) {
      var val = data[R][cols[C]];
      var cell = {v: val};
      if (typeof val === 'number') cell.t = 'n';
      else cell.t = 's';
      var cell_ref = encode_cell({c: C, r: R + 1});
      ws[cell_ref] = cell;
    }
  }
  
  range.e.r = data.length;
  range.e.c = cols.length - 1;
  ws['!ref'] = encode_range(range);
  
  return ws;
}

function encode_cell(cell) {
  return encode_col(cell.c) + encode_row(cell.r);
}

function encode_col(col) {
  var s = "";
  for (++col; col; col = Math.floor((col - 1) / 26)) {
    s = String.fromCharCode(((col - 1) % 26) + 65) + s;
  }
  return s;
}

function encode_row(row) {
  return "" + (row + 1);
}

function encode_range(range) {
  return encode_cell(range.s) + ":" + encode_cell(range.e);
}

function book_new() {
  return {SheetNames: [], Sheets: {}};
}

function book_append_sheet(wb, ws, name) {
  wb.SheetNames.push(name);
  wb.Sheets[name] = ws;
}

function write(wb, opts) {
  var o = opts || {};
  var type = o.type || 'base64';
  
  // 构建 XML
  var str = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\r\n';
  str += '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">\r\n';
  str += '<sheets>\r\n';
  for (var i = 0; i < wb.SheetNames.length; ++i) {
    str += '<sheet name="' + wb.SheetNames[i] + '" sheetId="' + (i + 1) + '"/>\r\n';
  }
  str += '</sheets>\r\n';
  str += '</workbook>\r\n';
  
  // 构建sheet XML
  for (var i = 0; i < wb.SheetNames.length; ++i) {
    var sheetName = wb.SheetNames[i];
    var ws = wb.Sheets[sheetName];
    str += sheet_to_xml(ws);
  }
  
  if (type === 'base64') {
    return wx.arrayBufferToBase64(s2ab(str));
  }
  return str;
}

function sheet_to_xml(ws) {
  var str = '<?xml version="1.0" encoding="UTF-8"?>\r\n';
  str += '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">\r\n';
  str += '<sheetData>\r\n';
  
  var range = decode_range(ws['!ref']);
  for (var R = range.s.r; R <= range.e.r; ++R) {
    str += '<row r="' + (R + 1) + '">\r\n';
    for (var C = range.s.c; C <= range.e.c; ++C) {
      var cell_ref = encode_cell({r: R, c: C});
      var cell = ws[cell_ref];
      if (cell) {
        var t = cell.t === 'n' ? 'n' : 'str';
        var v = String(cell.v).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        str += '<c r="' + cell_ref + '" t="' + t + '"><v>' + v + '</v></c>\r\n';
      }
    }
    str += '</row>\r\n';
  }
  
  str += '</sheetData>\r\n';
  str += '</worksheet>\r\n';
  return str;
}

function decode_range(range) {
  var x = range.split(":").map(decode_cell);
  return {s: x[0], e: x[x.length - 1]};
}

function decode_cell(cstr) {
  var c = 0, r = 0;
  for (var i = 0; i < cstr.length; ++i) {
    var cc = cstr.charCodeAt(i);
    if (cc >= 65 && cc <= 90) c = c * 26 + cc - 64;
    else if (cc >= 97 && cc <= 122) c = c * 26 + cc - 96;
    else r = r * 10 + cc - 48;
  }
  return {c: c - 1, r: r - 1};
}

// 公开 API
XLSX.utils = {
  json_to_sheet: json_to_sheet,
  encode_cell: encode_cell,
  encode_range: encode_range
};

XLSX.write = write;
XLSX.book_new = book_new;
XLSX.book_append_sheet = book_append_sheet;

// 导出
if (typeof module !== 'undefined') {
  module.exports = XLSX;
} else {
  window.XLSX = XLSX;
}
